mapper.update:
UPDATE blog SET blog_blogViews = blog_blogViews + CASE blog_id
WHEN #{item.id} THEN #{item.blogViews}
ELSE 0 END WHERE blog_id IN
#{item.id}

mapper.select:
SELECT blog_id,blog_title,blog_body,blog_discussCount,blog_blogViews,blog_time,blog_state,b.user_id,u.user_name,u.user_avatar
FROM blog b LEFT JOIN user u on b.user_id = u.user_id
WHERE blog_id = #{blogId}
